module gray_counter_N #(parameter WIDTH = 4) (input clock, input reset, input count, output [WIDTH-1:0] q);
  genvar i;
  generate
    for (i = 0; i < WIDTH; i = i + 1) begin : bits
      gray_counter_bit #(.BIT_idx(i)) bit_inst (.clk(clock), .rst(reset), .in(count), .out(q[i]));
    end
  endgenerate
endmodule

module wrapper #(parameter WIDTH = 4) (input clk, input rst, output [WIDTH-1:0] q);
  gray_counter_N #(.WIDTH(WIDTH)) cnt (.clock(clk), .reset(rst), .count(1'b1), .q(q));
endmodule
// When run with: verilator -GWIDTH=1 -Gdepth=1

module gray_counter_wrapper (input clk, input rst, output [7:0] q_structural);
  gray_counter_first #(.PREV(1'b0)) g0 (.clk(clk), .rst(rst), .q(q_structural[0]));
  gray_counter_N #(.BIT(1)) g1 (.clk(clk), .rst(rst), .q(q_structural[1]));
  gray_counter_last #(.BIT(7), .PREV(q_structural[6])) g7 (.clk(clk), .rst(rst), .q(q_structural[7]));
endmodule
